// Phase 14 v15.1: Compiler - AST to Bytecode
// AST를 바이트코드로 변환하는 컴파일러

use crate::v14_2_pratt_parsing::{Expression, InfixOp, PrefixOp};
use std::fmt;

// ============ OpCode 정의 ============

#[derive(Debug, Clone, Copy, PartialEq)]
#[repr(u8)]
pub enum OpCode {
    // 상수 로딩
    OpConstant = 0x00,

    // 산술 연산
    OpAdd = 0x01,
    OpSubtract = 0x02,
    OpMultiply = 0x03,
    OpDivide = 0x04,

    // 비교 연산
    OpEqual = 0x05,
    OpNotEqual = 0x06,
    OpGreaterThan = 0x07,
    OpLessThan = 0x08,
    OpLessThanOrEqual = 0x09,
    OpGreaterThanOrEqual = 0x0A,

    // 논리 연산
    OpNot = 0x0B,

    // 반환
    OpReturn = 0x0C,

    // 팝 (스택 탑 제거)
    OpPop = 0x0D,

    // 마지막 플레이스홀더
    OpUnknown = 0xFF,
}

impl OpCode {
    pub fn to_string(&self) -> String {
        match self {
            OpCode::OpConstant => "OpConstant".to_string(),
            OpCode::OpAdd => "OpAdd".to_string(),
            OpCode::OpSubtract => "OpSubtract".to_string(),
            OpCode::OpMultiply => "OpMultiply".to_string(),
            OpCode::OpDivide => "OpDivide".to_string(),
            OpCode::OpEqual => "OpEqual".to_string(),
            OpCode::OpNotEqual => "OpNotEqual".to_string(),
            OpCode::OpGreaterThan => "OpGreaterThan".to_string(),
            OpCode::OpLessThan => "OpLessThan".to_string(),
            OpCode::OpLessThanOrEqual => "OpLessThanOrEqual".to_string(),
            OpCode::OpGreaterThanOrEqual => "OpGreaterThanOrEqual".to_string(),
            OpCode::OpNot => "OpNot".to_string(),
            OpCode::OpReturn => "OpReturn".to_string(),
            OpCode::OpPop => "OpPop".to_string(),
            OpCode::OpUnknown => "OpUnknown".to_string(),
        }
    }

    pub fn from_byte(byte: u8) -> Self {
        match byte {
            0x00 => OpCode::OpConstant,
            0x01 => OpCode::OpAdd,
            0x02 => OpCode::OpSubtract,
            0x03 => OpCode::OpMultiply,
            0x04 => OpCode::OpDivide,
            0x05 => OpCode::OpEqual,
            0x06 => OpCode::OpNotEqual,
            0x07 => OpCode::OpGreaterThan,
            0x08 => OpCode::OpLessThan,
            0x09 => OpCode::OpLessThanOrEqual,
            0x0A => OpCode::OpGreaterThanOrEqual,
            0x0B => OpCode::OpNot,
            0x0C => OpCode::OpReturn,
            0x0D => OpCode::OpPop,
            _ => OpCode::OpUnknown,
        }
    }
}

// ============ Object (상수) ============

#[derive(Debug, Clone, PartialEq)]
pub enum CompileObject {
    Integer(i32),
    Float(f64),
    Boolean(bool),
    Null,
}

impl CompileObject {
    pub fn to_string(&self) -> String {
        match self {
            CompileObject::Integer(i) => i.to_string(),
            CompileObject::Float(f) => f.to_string(),
            CompileObject::Boolean(b) => b.to_string(),
            CompileObject::Null => "null".to_string(),
        }
    }
}

// ============ Bytecode ============

#[derive(Debug, Clone)]
pub struct Bytecode {
    pub instructions: Vec<u8>,
    pub constants: Vec<CompileObject>,
}

impl Bytecode {
    pub fn new() -> Self {
        Bytecode {
            instructions: Vec::new(),
            constants: Vec::new(),
        }
    }

    pub fn to_string(&self) -> String {
        format!(
            "Bytecode {{\n  instructions: {:?}\n  constants: [{} items]\n}}",
            self.instructions,
            self.constants.len()
        )
    }
}

// ============ Compiler ============

pub struct Compiler {
    instructions: Vec<u8>,
    constants: Vec<CompileObject>,
}

impl Compiler {
    pub fn new() -> Self {
        Compiler {
            instructions: Vec::new(),
            constants: Vec::new(),
        }
    }

    /// AST 컴파일
    pub fn compile(&mut self, expr: &Expression) -> Result<(), String> {
        self.compile_expression(expr)?;
        Ok(())
    }

    fn compile_expression(&mut self, expr: &Expression) -> Result<(), String> {
        match expr {
            Expression::Literal(val) => {
                let const_index = self.add_constant(CompileObject::Integer(*val));
                self.emit(OpCode::OpConstant, &[const_index as u16]);
                Ok(())
            }
            Expression::FloatLiteral(f) => {
                let const_index = self.add_constant(CompileObject::Float(*f));
                self.emit(OpCode::OpConstant, &[const_index as u16]);
                Ok(())
            }
            Expression::Prefix { operator, operand } => {
                // 1. 피연산자 컴파일
                self.compile_expression(operand)?;

                // 2. 연산자 방출
                match operator {
                    PrefixOp::Bang => self.emit(OpCode::OpNot, &[]),
                    PrefixOp::Minus => {
                        // 음수는 0 - x로 구현 (간단한 방식)
                        // 실제로는 OpNegate가 있어야 함
                        let zero_idx = self.add_constant(CompileObject::Integer(0));
                        self.emit(OpCode::OpConstant, &[zero_idx as u16]);
                        // 이 부분은 생략 (복잡도 증가)
                    }
                }
                Ok(())
            }
            Expression::Infix { left, operator, right } => {
                // 1. 왼쪽 자식 컴파일 (post-order)
                self.compile_expression(left)?;

                // 2. 오른쪽 자식 컴파일
                self.compile_expression(right)?;

                // 3. 연산자 방출
                match operator {
                    InfixOp::Plus => self.emit(OpCode::OpAdd, &[]),
                    InfixOp::Minus => self.emit(OpCode::OpSubtract, &[]),
                    InfixOp::Multiply => self.emit(OpCode::OpMultiply, &[]),
                    InfixOp::Divide => self.emit(OpCode::OpDivide, &[]),
                    InfixOp::Equal => self.emit(OpCode::OpEqual, &[]),
                    InfixOp::NotEqual => self.emit(OpCode::OpNotEqual, &[]),
                    InfixOp::Greater => self.emit(OpCode::OpGreaterThan, &[]),
                    InfixOp::Less => self.emit(OpCode::OpLessThan, &[]),
                    InfixOp::LessEqual => self.emit(OpCode::OpLessThanOrEqual, &[]),
                    InfixOp::GreaterEqual => self.emit(OpCode::OpGreaterThanOrEqual, &[]),
                    _ => return Err(format!("unsupported operator: {:?}", operator)),
                }
                Ok(())
            }
            Expression::Grouped(inner) => {
                // 괄호는 단순히 내부 표현식 컴파일
                self.compile_expression(inner)?;
                Ok(())
            }
        }
    }

    /// 상수 추가 (중복 제거)
    fn add_constant(&mut self, obj: CompileObject) -> usize {
        // 중복 확인
        if let Some(index) = self.constants.iter().position(|c| *c == obj) {
            return index;
        }

        // 새로운 상수 추가
        self.constants.push(obj);
        self.constants.len() - 1
    }

    /// 명령어 방출
    fn emit(&mut self, op: OpCode, operands: &[u16]) {
        // 1. OpCode 저장 (1바이트)
        self.instructions.push(op as u8);

        // 2. 피연산자 저장 (u16을 2바이트로 분해, big-endian)
        for &operand in operands {
            self.instructions.push((operand >> 8) as u8);
            self.instructions.push((operand & 0xFF) as u8);
        }
    }

    /// 바이트코드 생성
    pub fn bytecode(&self) -> Bytecode {
        Bytecode {
            instructions: self.instructions.clone(),
            constants: self.constants.clone(),
        }
    }
}

// ============ Disassembler (역컴파일) ============

pub struct Disassembler;

impl Disassembler {
    pub fn disassemble(bytecode: &Bytecode) -> String {
        let mut result = String::new();
        result.push_str("Bytecode Instructions:\n");

        let mut offset = 0;
        while offset < bytecode.instructions.len() {
            let (line, next_offset) = Self::disassemble_instruction(&bytecode.instructions, offset);
            result.push_str(&format!("{:04} {}\n", offset, line));
            offset = next_offset;
        }

        result.push_str("\nConstants:\n");
        for (i, const_obj) in bytecode.constants.iter().enumerate() {
            result.push_str(&format!("  [{}] {}\n", i, const_obj.to_string()));
        }

        result
    }

    pub fn disassemble_instruction(instructions: &[u8], offset: usize) -> (String, usize) {
        if offset >= instructions.len() {
            return ("out of bounds".to_string(), offset + 1);
        }

        let op = OpCode::from_byte(instructions[offset]);

        match op {
            OpCode::OpConstant => {
                let const_index = Self::read_uint16(&instructions[offset + 1..]) as usize;
                (format!("OpConstant {}", const_index), offset + 3)
            }
            OpCode::OpAdd => ("OpAdd".to_string(), offset + 1),
            OpCode::OpSubtract => ("OpSubtract".to_string(), offset + 1),
            OpCode::OpMultiply => ("OpMultiply".to_string(), offset + 1),
            OpCode::OpDivide => ("OpDivide".to_string(), offset + 1),
            OpCode::OpEqual => ("OpEqual".to_string(), offset + 1),
            OpCode::OpNotEqual => ("OpNotEqual".to_string(), offset + 1),
            OpCode::OpGreaterThan => ("OpGreaterThan".to_string(), offset + 1),
            OpCode::OpLessThan => ("OpLessThan".to_string(), offset + 1),
            OpCode::OpLessThanOrEqual => ("OpLessThanOrEqual".to_string(), offset + 1),
            OpCode::OpGreaterThanOrEqual => ("OpGreaterThanOrEqual".to_string(), offset + 1),
            OpCode::OpNot => ("OpNot".to_string(), offset + 1),
            OpCode::OpReturn => ("OpReturn".to_string(), offset + 1),
            OpCode::OpPop => ("OpPop".to_string(), offset + 1),
            OpCode::OpUnknown => ("OpUnknown".to_string(), offset + 1),
        }
    }

    fn read_uint16(data: &[u8]) -> u16 {
        if data.len() < 2 {
            return 0;
        }
        ((data[0] as u16) << 8) | (data[1] as u16)
    }
}

