// ============ Tests ============

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_compile_constant() {
        let expr = Expression::Literal(42);
        let mut compiler = Compiler::new();
        compiler.compile(&expr).unwrap();

        let bytecode = compiler.bytecode();
        assert_eq!(bytecode.constants.len(), 1);
        assert_eq!(bytecode.instructions.len(), 3);
        assert_eq!(bytecode.instructions[0], OpCode::OpConstant as u8);
    }

    #[test]
    fn test_compile_simple_addition() {
        let expr = Expression::Infix {
            left: Box::new(Expression::Literal(1)),
            operator: InfixOp::Plus,
            right: Box::new(Expression::Literal(2)),
        };

        let mut compiler = Compiler::new();
        compiler.compile(&expr).unwrap();

        let bytecode = compiler.bytecode();
        assert_eq!(bytecode.constants.len(), 2);
        assert_eq!(bytecode.constants[0], CompileObject::Integer(1));
        assert_eq!(bytecode.constants[1], CompileObject::Integer(2));

        // Instructions: OpConstant 0, OpConstant 1, OpAdd
        assert_eq!(bytecode.instructions.len(), 7);
    }

    #[test]
    fn test_constant_deduplication() {
        let expr = Expression::Infix {
            left: Box::new(Expression::Literal(5)),
            operator: InfixOp::Plus,
            right: Box::new(Expression::Literal(5)),
        };

        let mut compiler = Compiler::new();
        compiler.compile(&expr).unwrap();

        let bytecode = compiler.bytecode();
        // 5가 두 번 나와도 상수는 1개여야 함
        assert_eq!(bytecode.constants.len(), 1);
        assert_eq!(bytecode.constants[0], CompileObject::Integer(5));
    }

    #[test]
    fn test_compile_nested_expression() {
        let expr = Expression::Infix {
            left: Box::new(Expression::Grouped(Box::new(Expression::Infix {
                left: Box::new(Expression::Literal(5)),
                operator: InfixOp::Plus,
                right: Box::new(Expression::Literal(10)),
            }))),
            operator: InfixOp::Multiply,
            right: Box::new(Expression::Literal(2)),
        };

        let mut compiler = Compiler::new();
        compiler.compile(&expr).unwrap();

        let bytecode = compiler.bytecode();
        assert_eq!(bytecode.constants.len(), 3);
    }

    #[test]
    fn test_opcode_from_byte() {
        assert_eq!(OpCode::from_byte(0x00), OpCode::OpConstant);
        assert_eq!(OpCode::from_byte(0x01), OpCode::OpAdd);
        assert_eq!(OpCode::from_byte(0x05), OpCode::OpEqual);
        assert_eq!(OpCode::from_byte(0xFF), OpCode::OpUnknown);
    }

    #[test]
    fn test_disassemble_constant() {
        let mut compiler = Compiler::new();
        let expr = Expression::Literal(42);
        compiler.compile(&expr).unwrap();

        let bytecode = compiler.bytecode();
        let disassembled = Disassembler::disassemble(&bytecode);
        assert!(disassembled.contains("OpConstant"));
        assert!(disassembled.contains("42"));
    }

    #[test]
    fn test_compile_comparison() {
        let expr = Expression::Infix {
            left: Box::new(Expression::Literal(5)),
            operator: InfixOp::GreaterThan,
            right: Box::new(Expression::Literal(3)),
        };

        let mut compiler = Compiler::new();
        compiler.compile(&expr).unwrap();

        let bytecode = compiler.bytecode();
        assert_eq!(bytecode.constants.len(), 2);
        assert!(bytecode.instructions.iter().any(|&b| b == OpCode::OpGreaterThan as u8));
    }

    #[test]
    fn test_compile_division() {
        let expr = Expression::Infix {
            left: Box::new(Expression::Literal(10)),
            operator: InfixOp::Divide,
            right: Box::new(Expression::Literal(2)),
        };

        let mut compiler = Compiler::new();
        compiler.compile(&expr).unwrap();

        let bytecode = compiler.bytecode();
        assert!(bytecode.instructions.iter().any(|&b| b == OpCode::OpDivide as u8));
    }

    #[test]
    fn test_bytecode_to_string() {
        let bytecode = Bytecode {
            instructions: vec![0x00, 0x00, 0x00],
            constants: vec![CompileObject::Integer(5)],
        };

        let output = bytecode.to_string();
        assert!(output.contains("Bytecode"));
        assert!(output.contains("instructions"));
        assert!(output.contains("1 items"));
    }

    #[test]
    fn test_compile_object_equality() {
        let obj1 = CompileObject::Integer(42);
        let obj2 = CompileObject::Integer(42);
        let obj3 = CompileObject::Integer(43);

        assert_eq!(obj1, obj2);
        assert_ne!(obj1, obj3);
    }
}
